    const lineHtml = () => lines.map((line, index) => `<div class="pws-line pws-change-line" data-change-line="${index}"><label>${esc(l("Omschrijving", "Description", "Description"))}<input data-change-field="description" required value="${esc(line.description || "")}"></label><label>${esc(l("Aantal", "Quantité", "Quantity"))}<input data-change-field="qty" type="number" step="0.01" required value="${esc(line.qty == null ? 1 : line.qty)}"></label><label>${esc(l("Eenheidsprijs", "Prix unitaire", "Unit price"))}<input data-change-field="unitPrice" type="number" min="0" step="0.01" required value="${esc(line.unitPrice || 0)}"></label><label>${esc(l("Btw", "TVA", "VAT"))}<select data-change-field="vatRate">${[0, 6, 12, 21].map(value => `<option value="${value}" ${Number(line.vatRate == null ? 21 : line.vatRate) === value ? "selected" : ""}>${value}%</option>`).join("")}</select></label><button type="button" data-change-remove="${index}" aria-label="${esc(l("Lijn verwijderen", "Supprimer la ligne", "Remove line"))}">×</button></div>`).join("");
    setEditor(isEdit ? l("Scopewijziging bewerken", "Modifier la modification", "Edit scope change") : l("Meerwerk of minderwerk registreren", "Enregistrer une modification", "Register scope change"), l("Bouwdossier", "Dossier chantier", "Construction file"), `<form id="pwsChangeForm" class="pws-editor">${intro("±", l("Wijziging traceerbaar vastleggen", "Documenter la modification", "Record the change with traceability"), l("Gebruik een negatieve hoeveelheid voor minderwerk. Totalen, btw, soort en budgetimpact worden uitsluitend door de backend berekend.", "Utilisez une quantité négative pour les travaux en moins. Les totaux, la TVA, le type et l’impact budgétaire sont calculés uniquement par le backend.", "Use a negative quantity for a scope decrease. Totals, VAT, type and budget impact are calculated only by the backend."))}<div class="pws-form-grid"><div class="adm-form-group"><label>${esc(l("Project", "Projet", "Project"))}</label><select name="projectId" required>${optionRows(worksiteData.projects, change && change.projectId, row => `${row.number || ""} · ${row.name}`)}</select></div><div class="adm-form-group"><label>${esc(l("Titel", "Titre", "Title"))}</label><input name="title" value="${esc(change && change.title || "")}" placeholder="${esc(l("Bijvoorbeeld extra stopcontacten", "Par exemple prises supplémentaires", "For example additional outlets"))}"></div><div class="adm-form-group wide"><label>${esc(l("Reden en scope", "Raison et périmètre", "Reason and scope"))}</label><textarea name="reason" required>${esc(change && change.reason || "")}</textarea></div><div class="adm-form-group wide"><label class="pws-check"><input name="atRisk" type="checkbox" ${change && change.atRisk ? "checked" : ""}><span>${esc(l("Werk start uitzonderlijk vóór formele aanvaarding. Dit risico moet zichtbaar blijven.", "Les travaux commencent exceptionnellement avant l’acceptation formelle. Ce risque doit rester visible.", "Work exceptionally starts before formal acceptance. This risk must remain visible."))}</span></label></div></div><div class="adm-form-group"><label>${esc(l("Wijzigingslijnen", "Lignes de modification", "Change lines"))}</label><div id="pwsChangeLines" class="pws-line-list">${lineHtml()}</div><button type="button" class="adm-btn adm-btn-secondary adm-btn-sm" id="pwsAddChangeLine">+ ${esc(l("Lijn toevoegen", "Ajouter une ligne", "Add line"))}</button></div>${actionsRow()}</form>`, "product-wide");
