    const redraw = () => { lineHost.innerHTML = lineHtml(); bindLines(); };
    const bindLines = () => { lineHost.querySelectorAll("[data-change-field]").forEach(input => input.addEventListener("input", syncLines)); lineHost.querySelectorAll("[data-change-remove]").forEach(button => button.addEventListener("click", () => { syncLines(); if (lines.length > 1) lines.splice(Number(button.dataset.changeRemove), 1); redraw(); })); };
