  /* ── Contracten ────────────────────────────────────────── */
  const CONTRACT_TRANSITIONS = { draft: ["active", "ended"], active: ["paused", "cancelled", "expired", "ended"], paused: ["active", "cancelled", "ended"], cancelled: ["ended"], expired: ["active", "ended"], ended: [] };
