  /* ── Aankoop en leveranciers ───────────────────────────── */
  const PO_TRANSITIONS = { draft: ["for_approval", "approved", "cancelled"], for_approval: ["approved", "draft", "cancelled"], approved: ["sent", "cancelled"], sent: ["confirmed", "cancelled"], confirmed: ["partially_received", "received", "cancelled"], partially_received: ["received", "cancelled"], received: ["partially_invoiced", "invoiced", "closed"], partially_invoiced: ["invoiced", "closed"], invoiced: ["closed"], closed: [], cancelled: [] };
