  async function loadPurchasing() {
    const [suppliers, orders, projects, articles, venues] = await Promise.all([
      api("GET", "/suppliers"), api("GET", "/purchase_orders"), api("GET", "/projects").catch(() => ({ projects: [] })), api("GET", "/articles?selectable=1&includeArchived=1").catch(() => ({ articles: [] })), api("GET", "/venues").catch(() => ({ venues: [] })),
    ]);
    return { suppliers: suppliers.suppliers || [], orders: orders.purchaseOrders || [], projects: projects.projects || [], articles: articles.articles || [], venues: venues.venues || [] };
  }

