    const form = document.getElementById("pwsReceiptForm"); bindCancel(form); form.addEventListener("submit", async event => { event.preventDefault(); const receipts = [...form.querySelectorAll("[data-receipt-line]")].map(row => ({ lineId: row.dataset.receiptLine, qty: Number(row.querySelector("[data-receipt-qty]").value || 0) })).filter(row => row.qty > 0); const locationId = new FormData(form).get("locationId") || undefined; const result = await save(() => api("POST", `/purchase_orders/${order.id}/receive`, { receipts, locationId }), renderPurchasing); if (!result) return; A.closeDrawer(); await renderPurchasing(); toast(l("Ontvangst geboekt", "Réception enregistrée", "Receipt booked")); });
