    setEditor(l("Voorraad tellen", "Compter le stock", "Count inventory"), l("Voorraadwerkruimte", "Espace stock", "Inventory workspace"), `<form id="pwsCountForm" class="pws-editor">${intro("#", l("Werkelijke voorraad registreren", "Enregistrer le stock réel", "Record actual inventory"), l("Vul de werkelijk getelde hoeveelheid in. De backend vergelijkt die met de fysieke stand en boekt alleen noodzakelijke verschilmutaties.", "Indiquez la quantité réellement comptée. Le backend la compare au stock physique et n’enregistre que les écarts nécessaires.", "Enter the quantity actually counted. The backend compares it with physical stock and only books required adjustment movements."))}<div id="pwsCountLines" class="pws-line-list">${rowHtml()}</div><button type="button" class="adm-btn adm-btn-secondary adm-btn-sm" id="pwsAddCountLine">+ ${esc(l("Telregel toevoegen", "Ajouter une ligne de comptage", "Add count row"))}</button>${actionsRow(l("Telling boeken", "Enregistrer le comptage", "Book count"))}</form>`, "product-wide");
    const form = document.getElementById("pwsCountForm"); const host = document.getElementById("pwsCountLines"); bindCancel(form);
