    const bindRows = () => { host.querySelectorAll("[data-count-field]").forEach(input => input.addEventListener("input", sync)); host.querySelectorAll("[data-count-remove]").forEach(button => button.addEventListener("click", () => { sync(); if (counts.length > 1) counts.splice(Number(button.dataset.countRemove), 1); redraw(); })); };
