    setEditor(isEdit ? l("Onderhoudsschema bewerken", "Modifier le plan de maintenance", "Edit maintenance plan") : l("Nieuw onderhoudsschema", "Nouveau plan de maintenance", "New maintenance plan"), l("Servicewerkruimte", "Espace service", "Service workspace"), `<form id="pwsPlanForm" class="pws-editor">${intro("O", l("Periodiek onderhoud plannen", "Planifier la maintenance périodique", "Plan periodic maintenance"), l("Een generatie maakt idempotent een werkbon met de bewaarde checklist.", "Une génération crée de manière idempotente une intervention avec la liste enregistrée.", "A generation idempotently creates a work order with the stored checklist."))}<div class="pws-form-grid"><div class="adm-form-group"><label>${esc(l("Asset", "Actif", "Asset"))}</label><select name="assetId" required>${optionRows(assetData.assets, plan && plan.assetId || assetId, row => `${row.name}${row.serial ? ` · ${row.serial}` : ""}`)}</select></div><div class="adm-form-group"><label>${esc(l("Titel", "Titre", "Title"))}</label><input name="title" required value="${esc(plan && plan.title || l("Periodiek onderhoud", "Maintenance périodique", "Periodic maintenance"))}"></div><div class="adm-form-group"><label>${esc(l("Frequentie", "Fréquence", "Frequency"))}</label><select name="frequency">${["monthly", "quarterly", "semiannual", "annual", "biennial"].map(value => `<option value="${value}" ${plan && plan.frequency === value ? "selected" : ""}>${esc(value)}</option>`).join("")}</select></div><div class="adm-form-group"><label>${esc(l("Volgende datum", "Prochaine date", "Next date"))}</label><input name="nextDue" type="date" required value="${esc(plan && plan.nextDue || today())}"></div><div class="adm-form-group"><label>${esc(l("Basis", "Base", "Basis"))}</label><select name="basis"><option value="calendar" ${plan && plan.basis === "calendar" ? "selected" : ""}>${esc(l("Vaste kalender", "Calendrier fixe", "Fixed calendar"))}</option><option value="execution" ${plan && plan.basis === "execution" ? "selected" : ""}>${esc(l("Vanaf uitvoering", "À partir de l’exécution", "From execution"))}</option></select></div><div class="adm-form-group"><label>${esc(l("Status", "Statut", "Status"))}</label><select name="status">${["draft", "active", "paused", "ended"].map(value => `<option value="${value}" ${plan && plan.status === value ? "selected" : ""}>${esc(statusLabel(value))}</option>`).join("")}</select></div><div class="adm-form-group"><label>${esc(l("Contract", "Contrat", "Contract"))}</label><select name="contractId">${optionRows(assetData.contracts, plan && plan.contractId, row => `${row.number || ""} · ${row.title}`, l("Geen contract", "Aucun contrat", "No contract"))}</select></div><div class="adm-form-group wide"><label>${esc(l("Checklist, één punt per regel", "Liste, un point par ligne", "Checklist, one item per line"))}</label><textarea name="checklist">${esc((plan && plan.checklist || []).join("\n"))}</textarea></div><div class="adm-form-group wide"><label>${esc(l("Notities", "Notes", "Notes"))}</label><textarea name="notes">${esc(plan && plan.notes || "")}</textarea></div></div>${actionsRow()}</form>`);
